var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"저쪽에서 또 몰려오고 있어!","JPN":"向こうからまた押し寄せてくる！","ENG":"There's a bunch of them coming at us over there!","TWN":"那邊也湧上來了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"도, 도대체 얼마나 많은 거예요?! 잡아도 잡아도 끝이 안 나잖아요!","JPN":"い、いったいどれだけいるんですか！？　倒しても倒してもキリがないですわ！","ENG":"Th-there's too many of them! It's never going to end this way!","TWN":"到、到底有多少啊？！這不是怎麼打都沒有止盡嗎！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"만세! 너무 좋다, 정말!","JPN":"万歳！　やったね、ラッキー！","ENG":"Yay! This is super fun!","TWN":"萬歲！真是太棒了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그냥 콱 나가 죽어 버리지 그래요!","JPN":"いっそあの化け物にやられちゃってください！","ENG":"I hope one of them bites you in the butt!","TWN":"我們直接出去，把它們全部解決掉吧！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그 아이들이 영지에서 가까운 도시에 살던 사람들을 모두 흡수해 버렸나 봐요.","JPN":"あの子たちが領地から近い都市に住む人たちを全員吸収してしまったようですね。","ENG":"The babies must have absorbed everyone living in that nearby town.","TWN":"看來那些孩子把生活在領地附近城市裡的人們全部吸收了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"정말...... 못 말리는 욕심쟁이네요.","JPN":"本当に……飽きれるほどの食欲です。","ENG":"They're like mad piglets looking for food.","TWN":"真是的……真是貪心得誰都擋不住啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이건......?","JPN":"これは……？","ENG":"This is...","TWN":"這是……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"리벳, 방금 뭔가 못 느꼈어요?!","JPN":"リベット、今何か感じませんでしたか！？","ENG":"Did you feel that, Rivet?","TWN":"里維，妳剛才沒感覺到什麼嗎？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제단 방향에서 뭔가 불길한 일이 벌어지는 것 같아요!","JPN":"祭壇の方で何か不吉なことが起きているようです！","ENG":"Something ominous is going on near the altar!","TWN":"祭壇那邊好像發生了什麼不祥的事情！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"미안! 나 지금 한창 인생을 만끽하는 중이라! 메시지만 남겨 줘!","JPN":"ごめん！　アタシ、今人生を満喫してるところなの！　後で聞くから！","ENG":"I'm sorry, I'm having the time of my life right now. If you have something to say, leave a message!","TWN":"抱歉！我現在正在盡情享受人生！幫我留個言吧！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"으으...... 정말!","JPN":"うぅ……もうっ！","ENG":"Oh, come on!","TWN":"噢……真是的！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델, 당신이라면 길을 열어 줄 수 있죠?!","JPN":"エデル、あなたなら道を切り開けますわね！？","ENG":"Edel, can you open the path for me?","TWN":"艾瑟兒，妳能幫我開一條路嗎？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"네? 급한 심정이신 줄은 알지만 이런 만찬을 두고 그냥 가면 예의가 아니잖아요?","JPN":"え？　急ぎたい気持ちはわかりますが、こんなご馳走を置いていくのは礼儀に反するのでは？","ENG":"Sorry? We know you're in a hurry, but it'd be very impolite of us to walk away from this grand feast.","TWN":"什麼？雖然我們了解您焦急的心情，但放著這種晚餐不管直接走掉，有點沒禮貌吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"지금 그런 헛소리를 할 때가 아니라고!","JPN":"今はそんなことを言ってる場合じゃありません！","ENG":"Now's not the time!","TWN":"現在不是說這種鬼話的時候！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"잘 들어요, 에델.","JPN":"エデル、よく聞いてください。","ENG":"Listen to me, Edel.","TWN":"聽好了，艾瑟兒。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"나도 설명하긴 어렵지만...... 당장 제단으로 가야 할 것 같아요!","JPN":"私も何と説明すればいいのかわかりませんが……今すぐ祭壇に行くべきです！","ENG":"It's hard to explain, but something very bad is going to happen","TWN":"雖然我很難解釋……但我認為我們得立刻去祭壇！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그렇지 않으면 아주 나쁜 일이 생길 것 같은 예감이......","JPN":"さもないと、とてつもなく悪いことが起きそうな予感が……","ENG":"if we don't get to the altar as soon as possible.","TWN":"不然的話，我有預感會發生很不好的事情……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저건......?","JPN":"あれは……？","ENG":"That's...","TWN":"那個……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"차원함선이잖아......? 혹시 관리국이 이변을 알아채고 보낸 건가?","JPN":"次元艦船……？　もしや、管理局が異変に気付いて送り込んだ……？","ENG":"A dimension ship? The Administration must have noticed something was wrong and sent us help!","TWN":"那不是次元艦船嗎……？難道是管理局發現了這裡的異變，所以派過來的？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이봐요! 여기 도움이 필요해요!","JPN":"こちらです！　助けてください！","ENG":"Hey! We need help here!","TWN":"喂！這裡需要幫助！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"듣고 있어요? 여기 사람들이......?!","JPN":"聞いてますか？　ここの人たちが……！？","ENG":"Can you hear me? There are people here—ouch!","TWN":"聽到了嗎？這裡的人……？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"리벳?! 이런 상황에서 절 넘어트리다니 무슨 짓이에요!","JPN":"リベット！？　こんな状況で私を転ばせるなんて、どういうことですか！","ENG":"Rivet! What did you push me down for?","TWN":"里維？！在這種情況下竟然絆倒我，妳是想幹什麼！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"멍하니 있지 마! 살고 싶으면 엎드려!","JPN":"ボケっとしてるんじゃないよ！　死にたくなかったら伏せな！","ENG":"Are you suicidal? Keep your head down if you want to live!","TWN":"別發呆了！不想死的話就趴好！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네? 무슨 말을......?!","JPN":"え？　何を……！？","ENG":"Sorry? What are you talking about?","TWN":"咦？妳說什麼……？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"알비온 호 함교에서 전파드립니다.","JPN":"アルビオン号の艦橋からお伝えします。","ENG":"Attention crew, this is the Albion bridge.","TWN":"來自阿爾比恩號的廣播。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_UI_DECK_UNIIT_SELECT"},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"본 함선은 현재 현실중첩형 봉쇄 좌표, <color=#ffd34c>맥크레디 포인트</color>에 성공적으로 진입한 상태입니다.","JPN":"当艦船は現在、現実重畳型封鎖座標、<color=#ffd34c>マクレディーポイント</color>への入域に成功しました。","ENG":"This ship has arrived at the dimensional superposition sealing coordinates, otherwise known as <color=#ffd34c>MacCready Point</color>.","TWN":"本艦目前成功進入現世重疊型封鎖座標，<color=#ffd34c>麥克蕾蒂要點</color>。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"카운터가 아닌 승무원은 외부 관측시 시각 필터를 사용해 주십시오. ","JPN":"カウンター以外の乗務員が外部を観測する際は、視覚フィルターをご使用ください。 ","ENG":"Be advised that all non-Counter crew must use vision filters when observing the operation area. ","TWN":"非制裁者的乘務員在觀測外部時，請使用視覺濾鏡。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"육안으로 관측할 경우 정신 이상 증세가 나타날 수 있습니다.","JPN":"肉眼で観測すると、精神異常の症状が現れる可能性があります。","ENG":"Keep in mind that naked eye observation may lead to various mental disorders.","TWN":"用肉眼觀測可能會出現精神異常症狀。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기록에 있던 대로 경치는 현실과 다를 바 없군요.","JPN":"記録にあった通り、見た目は現実と変わりませんわね。","ENG":"Just like the record said, everything looks as real as it gets.","TWN":"和記錄中一樣，這裡的風景和現世沒什麼區別啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이면세계와 현실을 중첩시켜서 본거지로 삼다니, 천박하지만 무척 효율적이네요.","JPN":"裏世界と現実を重ねて本拠地とするなんて馬鹿げていますが、とても効率的な発想でした。","ENG":"They've built their base in the overlap between the Normalside and the Counterside. It's a pathetic but highly efficient idea.","TWN":"竟然將異界與現世重疊並當作據點，儘管膚淺，卻非常有效率呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇습니다. 진입 좌표 없이는 차원 함선으로도 진입이 불가능한 철옹성이죠.","JPN":"そうですね。侵入座標が無くては次元艦船でも入ることすらできない鉄の城です。","ENG":"Indeed. Even dimension ships can't approach it without coordinates. It's basically impregnable.","TWN":"是的。如果沒有進入座標，就算是次元艦船也無法進入的銅牆鐵壁呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"오래된 목소리의 정보가 아니었다면 들어오지 못했을 겁니다.","JPN":"古き声の情報が無ければ、我々も入れなかったでしょう。","ENG":"We wouldn't be here if it weren't for the information the Old Voice gave us.","TWN":"如果沒有老聲音的情報，我們也無法進入吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그쪽에서 연락할 때마다 문제가 터지는데, 차라리 불행의 목소리라고 부르는 게 더 어울리지 않겠나?","JPN":"向こうから連絡が来るたびに問題が起こるんだから、いっそ不幸の声とでも呼んだ方がいいんじゃないか？","ENG":"Something serious comes up every time we receive a call. I think Voice of Misfortune would be a more appropriate name.","TWN":"那邊每次有聯絡都會發生問題，乾脆叫不幸的聲音如何？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"전화기 너머에 있는 게 누구인지는 모르겠지만 반가워 하기 어려운 작자인 건 분명해.","JPN":"受話器の向こうにいるのが誰なのかは知らんが、あまり歓迎できない相手であるのは確かだな。","ENG":"I don't welcome the news that this person brings us, whoever it may be.","TWN":"雖然不知道電話另一端的人是誰，但確實很難歡迎他呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"동감일세. 하지만 신뢰할 수 있는 협력자라는 것도 사실이지.","JPN":"同感です。だが、信頼できる協力者であるのも事実。","ENG":"I agree. But you have to admit, this person is a very reliable ally.","TWN":"我也有同感。不過他是個值得信賴的協力者也是事實。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"오래된 목소리라면 분명 구 관리국과의 비상 연락망이라고 들었어요.","JPN":"古き声というのは、確か旧管理局との非常連絡網だと聞きましたけど。","ENG":"I heard the Old Voice was the emergency communication network connected to the Old Administration.","TWN":"我聽說老聲音是舊管理局的緊急聯絡網。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"관리 실패 이후로 연결은 전부 두절됐을 텐데......","JPN":"管理に失敗してから連絡は全て途絶えたはずですが……","ENG":"And all the lines were known to have been cut off after the Administration Failure.","TWN":"明明管理失敗後所有連絡都中斷了……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"다시 연락이 오다니 흥미롭네요.","JPN":"また連絡が来たとは、興味深いですわね。","ENG":"I find it interesting that it's working again.","TWN":"但竟然又會有連絡過來，真是耐人尋味呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐, 지금 흥미를 쏟으셔야 할 상대는 따로 있는 것 같군요.","JPN":"まあ、今興味を持つべき相手は別にいるようですがね。","ENG":"Well, there's something else that you should invest your interest in.","TWN":"不過，我們現在應該有別的該關注的對象。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"잔해들은 탐식자의 허수 에너지로 만들어진 존재들입니다.","JPN":"残骸は貪食者の虚数エネルギーにより作られた存在です。","ENG":"The Remains are beings created from the Imaginary Energy of the Devourer.","TWN":"殘骸是由貪食者的虛數能量創造的存在。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"함포 사격만으로는 깨끗이 소탕하기 어렵겠죠. 카운터가 나서야 할 때로군요.","JPN":"艦砲の射撃だけでは完全に掃討することはできないでしょう。カウンターの出番ですな。","ENG":"Cannons on this ship won't be enough to eradicate them all. It's time for Counters to step in.","TWN":"光靠艦船炮擊很難把它們消滅乾淨吧。是制裁者出馬的時候了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그래요. 머릿수도 상당하네요.","JPN":"そうですわね。頭数もかなり多いですし。","ENG":"Indeed. And they are huge in number.","TWN":"沒錯。數量也不少呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"가까운 소도시에서 급성 침식 재난이 발생했다는 보고가 있었습니다.","JPN":"近くの小都市で急性侵食災害が発生したという報告がありました。","ENG":"There has been a report of an acute Corruption Disaster in a small town near here.","TWN":"有報告說附近小城市中發生急性侵蝕災難。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"아무래도...... 저희보다 한 발 앞서 세를 불리기 시작한 모양입니다.","JPN":"どうやら……我々よりも一足早く数を増やし始めたようです。","ENG":"I'm afraid they had started building up their strength before we came.","TWN":"不管怎麼說……看來它比我們快了一步，已經開始壯大實力了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"......그렇다면 더 지체할 이유는 없죠.","JPN":"……ならば、これ以上待つ理由はありませんわ。","ENG":"Then there's no point in dilly-dallying here.","TWN":"……那就沒有再拖下去的理由了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"탐식자를 영원히 잠재우는 것이야말로 기관의 숙업.","JPN":"貪食者を永遠に眠らせることこそ、機関の使命。","ENG":"The Institution exist to keep the Devourer sealed.","TWN":"讓貪食者永眠正是機關的宿業。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"지금 이곳에서, 여왕 폐하의 이름 아래 정화 작전의 개시를 선포하겠습니다.","JPN":"今ここで、女王陛下の名の下に浄化作戦の開始を宣布します。","ENG":"In the name of the Queen, I hereby announce the commencement of the Purification Operation.","TWN":"現在在這裡，我以女王陛下之名宣佈，淨化作戰開始。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"전부, 태워 버리세요.","JPN":"全部、燃やしてしまいなさい。","ENG":"Everything shall be burnt to ashes.","TWN":"將一切都燒盡吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};